INSERT INTO profil_metier (id, code, libelle, description, statut) VALUES (900101, 'ADMINISTRATEUR', 'Administrateur', 'Acces complet a la plateforme', 'ACTIF'), (900102, 'MANAGER_ADM', 'Manager ADM', 'Creation des boutiques, gestion des acces, redevances, reporting et supervision ADM', 'ACTIF'), (900103, 'MANAGER_BOUTIQUE', 'Manager boutique', 'Exploitation operationnelle d''une boutique', 'ACTIF'), (900104, 'VENDEUR', 'Vendeur', 'Encaissement et ventes en boutique', 'ACTIF') ON CONFLICT (code) DO UPDATE SET libelle = EXCLUDED.libelle, description = EXCLUDED.description, statut = EXCLUDED.statut;
INSERT INTO permission_metier (id, code, libelle, module, description) VALUES (900001, 'USER_READ', 'Consulter les utilisateurs', 'UTILISATEURS', null), (900002, 'USER_CREATE', 'Creer les utilisateurs', 'UTILISATEURS', null), (900003, 'USER_UPDATE', 'Modifier les utilisateurs', 'UTILISATEURS', null), (900004, 'USER_DEACTIVATE', 'Desactiver les utilisateurs', 'UTILISATEURS', null), (900005, 'USER_MANAGE', 'Administrer les utilisateurs', 'UTILISATEURS', null), (900010, 'SALES_READ', 'Consulter les ventes', 'CAISSE', null), (900011, 'SALES_MANAGE', 'Gerer les ventes', 'CAISSE', null), (900020, 'STOCK_READ', 'Consulter le stock', 'STOCK', null), (900021, 'STOCK_MANAGE', 'Gerer le stock', 'STOCK', null), (900030, 'REPORTING_READ', 'Consulter le reporting', 'REPORTING', null), (900031, 'REPORTING_EXPORT', 'Exporter le reporting', 'REPORTING', null), (900040, 'ROYALTY_READ', 'Consulter les redevances', 'REDEVANCES', null), (900041, 'ROYALTY_MANAGE', 'Gerer les redevances', 'REDEVANCES', null), (900050, 'SETTINGS_READ', 'Consulter les parametres', 'PARAMETRES', null), (900051, 'SETTINGS_MANAGE', 'Gerer les parametres', 'PARAMETRES', null), (900060, 'AUDIT_READ', 'Consulter audit et supervision', 'AUDIT', null) ON CONFLICT (code) DO UPDATE SET libelle = EXCLUDED.libelle, module = EXCLUDED.module;
-- Final permission set per role (already reflects 20260611120000_enforce_manager_adm_scope -- and this repo's 20260630090000_restrict_manager_boutique_settings_audit). INSERT INTO rel_profil_metier__permissions (profil_metier_id, permissions_id) SELECT profil.id, permission.id FROM profil_metier profil JOIN permission_metier permission ON permission.code IN ( 'USER_READ','USER_CREATE','USER_UPDATE','USER_DEACTIVATE','USER_MANAGE', 'SALES_READ','SALES_MANAGE','STOCK_READ','STOCK_MANAGE', 'REPORTING_READ','REPORTING_EXPORT','ROYALTY_READ','ROYALTY_MANAGE', 'SETTINGS_READ','SETTINGS_MANAGE','AUDIT_READ' ) WHERE profil.code = 'ADMINISTRATEUR' ON CONFLICT DO NOTHING;
INSERT INTO rel_profil_metier__permissions (profil_metier_id, permissions_id) SELECT profil.id, permission.id FROM profil_metier profil JOIN permission_metier permission ON permission.code IN ( 'USER_READ','USER_CREATE','USER_UPDATE','USER_DEACTIVATE','USER_MANAGE', 'SALES_READ','REPORTING_READ','REPORTING_EXPORT','ROYALTY_READ','ROYALTY_MANAGE', 'SETTINGS_READ','SETTINGS_MANAGE','AUDIT_READ' ) WHERE profil.code = 'MANAGER_ADM' ON CONFLICT DO NOTHING;
INSERT INTO rel_profil_metier__permissions (profil_metier_id, permissions_id) SELECT profil.id, permission.id FROM profil_metier profil JOIN permission_metier permission ON permission.code IN ( 'USER_READ','USER_CREATE','USER_UPDATE','USER_DEACTIVATE', 'SALES_READ','SALES_MANAGE','STOCK_READ','STOCK_MANAGE','REPORTING_READ','ROYALTY_READ' ) WHERE profil.code = 'MANAGER_BOUTIQUE' ON CONFLICT DO NOTHING;
INSERT INTO rel_profil_metier__permissions (profil_metier_id, permissions_id) SELECT profil.id, permission.id FROM profil_metier profil JOIN permission_metier permission ON permission.code IN ('SALES_READ','SALES_MANAGE') WHERE profil.code = 'VENDEUR' ON CONFLICT DO NOTHING;
