-- password "admin" for every test account below (same bcrypt hash as the seeded jhi_user admin row). INSERT INTO jhi_user (id, login, password_hash, first_name, last_name, email, activated, lang_key, created_by, last_modified_by, must_change_password) VALUES (901201, 'manager_adm', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Manager', 'ADM', 'manager.adm@test.adm', true, 'fr', 'system', 'system', false), (901202, 'manager_alpha', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Manager', 'Alpha', 'manager.alpha@test.adm', true, 'fr', 'system', 'system', false), (901203, 'manager_beta', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Manager', 'Beta', 'manager.beta@test.adm', true, 'fr', 'system', 'system', false), (905001, 'vendeur_alpha', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Vendeur', 'Alpha', 'vendeur.alpha@test.adm', true, 'fr', 'system', 'system', false), (905002, 'vendeur_beta', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Vendeur', 'Beta', 'vendeur.beta@test.adm', true, 'fr', 'system', 'system', false), (905003, 'loc_alpha', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Locataire', 'Alpha', 'loc.alpha@test.adm', true, 'fr', 'system', 'system', true), (905004, 'loc_beta', '$2a$10$gSAhZrxMllrbgj/kkK9UceBPpChGWJA7SYIb1Mqo.n5aNLq1/oRrC', 'Locataire', 'Beta', 'loc.beta@test.adm', true, 'fr', 'system', 'system', true) ON CONFLICT (login) DO UPDATE SET password_hash = EXCLUDED.password_hash, activated = EXCLUDED.activated, must_change_password = EXCLUDED.must_change_password;
INSERT INTO jhi_user_authority (user_id, authority_name) SELECT id, 'ROLE_USER' FROM jhi_user WHERE login IN ('manager_adm','manager_alpha','manager_beta','vendeur_alpha','vendeur_beta','loc_alpha','loc_beta') ON CONFLICT DO NOTHING; INSERT INTO jhi_user_authority (user_id, authority_name) SELECT id, 'ROLE_VENDEUR' FROM jhi_user WHERE login IN ('vendeur_alpha','vendeur_beta') ON CONFLICT DO NOTHING; INSERT INTO jhi_user_authority (user_id, authority_name) SELECT id, 'ROLE_LOCATAIRE' FROM jhi_user WHERE login IN ('loc_alpha','loc_beta') ON CONFLICT DO NOTHING;
