r p WHERE u.login = 'vendeur_alpha' AND b.code = 'ADM-BTK-01' AND p.code = 'VENDEUR' ON CONFLICT (id) DO UPDATE SET actif = EXCLUDED.actif, user_id = EXCLUDED.user_id, boutique_id = EXCLUDED.boutique_id, profil_id = EXCLUDED.profil_id; INSERT INTO affectation_utilisateur (id, date_debut, date_fin, actif, user_id, boutique_id, profil_id) SELECT 905102, DATE '2026-01-01', null, true, u.id, b.id, p.id FROM jhi_user u, boutique b, profil_metier p WHERE u.login = 'vendeur_beta' AND b.code = 'ADM-BTK-02' AND p.code = 'VENDEUR' ON CONFLICT (id) DO UPDATE SET actif = EXCLUDED.actif, user_id = EXCLUDED.user_id, boutique_id = EXCLUDED.boutique_id, profil_id = EXCLUDED.profil_id;
